1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<readonly [number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = (x: number, y: number): string => `${x},${y}`;
10	
11	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
12	  const liveKeys = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
13	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
14	
15	  for (const [x, y] of liveCells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const nx = x + dx;
18	      const ny = y + dy;
19	      const key = cellKey(nx, ny);
20	      const entry = neighborCounts.get(key);
21	      if (entry) entry.count += 1;
22	      else neighborCounts.set(key, { cell: [nx, ny], count: 1 });
23	    }
24	  }
25	
26	  const nextCells: Cell[] = [];
27	  for (const [key, { cell, count }] of neighborCounts) {
28	    const alive = liveKeys.has(key);
29	    if ((alive && (count === 2 || count === 3)) || (!alive && count === 3)) {
30	      nextCells.push(cell);
31	    }
32	  }
33	  return nextCells;
34	};
