1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return an empty array when given an empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) as a still life", () => {
15	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(input);
17	    expect(new Set(result.map((c) => `${c[0]},${c[1]}`))).toEqual(
18	      new Set(input.map((c) => `${c[0]},${c[1]}`))
19	    );
20	  });
21	  it("should oscillate a vertical blinker to horizontal", () => {
22	    const input: [number, number][] = [[0, 0], [0, 1], [0, 2]];
23	    const expected: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
24	    const result = nextGeneration(input);
25	    expect(new Set(result.map((c) => `${c[0]},${c[1]}`))).toEqual(
26	      new Set(expected.map((c) => `${c[0]},${c[1]}`))
27	    );
28	  });
29	  it("should bring a dead cell with exactly 3 neighbors to life (reproduction)", () => {
30	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
31	    const result = nextGeneration(input);
32	    const keys = new Set(result.map((c) => `${c[0]},${c[1]}`));
33	    expect(keys.has("1,1")).toBe(true);
34	  });
35	  it.todo("should kill a live cell with more than 3 neighbors (overpopulation)");
36	  it.todo("should handle negative coordinates");
37	});
